-- N5 語彙コース: Unit 1-3（12レッスン）
-- ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

-- ================================
-- Unit 1: あいさつ・基本表現（Lesson 1-4）
-- ================================

-- Lesson 1-1: 基本的なあいさつ
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 1-1: 基本的なあいさつ", "vi": "Unit 1-1: Lời chào cơ bản"}',
  '{"type": "vocabulary", "unit": 1, "lesson_number": 1, "intro": {"ja": "今日は基本的なあいさつを学びましょう！介護の現場でも毎日使います。", "vi": "Hôm nay chúng ta sẽ học các lời chào cơ bản! Chúng được sử dụng hàng ngày trong môi trường chăm sóc."}, "words": [{"word": "おはようございます", "reading": "おはようございます", "kanji": null, "meaning": {"vi": "Xin chào (buổi sáng)", "ja": "朝のあいさつ"}, "examples": [{"ja": "おはようございます。今日もよろしくお願いします。", "vi": "Xin chào buổi sáng. Hôm nay cũng xin hãy giúp đỡ."}, {"ja": "先生、おはようございます。", "vi": "Chào buổi sáng, thầy/cô."}], "care_example": {"ja": "利用者さんの部屋に入る時：「○○さん、おはようございます。体調はいかがですか？」", "vi": "Khi vào phòng người được chăm sóc: '○○ san, ohayou gozaimasu. Taichou wa ikaga desu ka?'"}}, {"word": "こんにちは", "reading": "こんにちは", "kanji": null, "meaning": {"vi": "Xin chào (ban ngày)", "ja": "昼間のあいさつ"}, "examples": [{"ja": "こんにちは。お疲れ様です。", "vi": "Xin chào. Cảm ơn bạn đã làm việc."}, {"ja": "田中さん、こんにちは。", "vi": "Tanaka san, xin chào."}], "care_example": {"ja": "午後の訪問時：「こんにちは。お昼のお薬の時間ですよ。」", "vi": "Khi ghé thăm chiều: 'Xin chào. Đã đến giờ uống thuốc trưa rồi ạ.'"}}, {"word": "こんばんは", "reading": "こんばんは", "kanji": null, "meaning": {"vi": "Xin chào (buổi tối)", "ja": "夕方・夜のあいさつ"}, "examples": [{"ja": "こんばんは。今日も一日お疲れ様でした。", "vi": "Xin chào tối. Cảm ơn bạn đã làm việc cả ngày."}, {"ja": "おばあさん、こんばんは。", "vi": "Bà ơi, xin chào tối."}], "care_example": {"ja": "夜間ケア時：「こんばんは。今からお風呂の準備をします。」", "vi": "Khi chăm sóc tối: 'Xin chào tối. Bây giờ chúng ta chuẩn bị tắm nhé.'"}}, {"word": "おやすみなさい", "reading": "おやすみなさい", "kanji": null, "meaning": {"vi": "Chúc ngủ ngon", "ja": "寝る前のあいさつ"}, "examples": [{"ja": "おやすみなさい。明日もよろしくお願いします。", "vi": "Chúc ngủ ngon. Ngày mai cũng xin hãy giúp đỡ."}, {"ja": "○○さん、おやすみなさい。", "vi": "○○ san, chúc ngủ ngon."}], "care_example": {"ja": "就寝時：「○○さん、おやすみなさい。朝までぐっすり眠ってくださいね。」", "vi": "Khi đi ngủ: '○○ san, chúc ngủ ngon. Hãy ngủ kỹ đến sáng nhé.'"}}, {"word": "さようなら", "reading": "さようなら", "kanji": null, "meaning": {"vi": "Tạm biệt", "ja": "別れの時のあいさつ"}, "examples": [{"ja": "では、さようなら。また明日。", "vi": "Thế thì tạm biệt. Hẹn gặp lại ngày mai."}, {"ja": "田中さん、さようなら。", "vi": "Tanaka san, tạm biệt."}], "care_example": {"ja": "勤務終了時：「では今日はここまでです。さようなら。明日もまた来ます。」", "vi": "Khi kết thúc ca: 'Thế thì hôm nay chỉ đến đây. Tạm biệt. Ngày mai tôi sẽ lại đến.'"}}, {"word": "よろしくお願いします", "reading": "よろしくおねがいします", "kanji": null, "meaning": {"vi": "Xin hãy giúp đỡ / Xin hãy chăm sóc", "ja": "丁寧にお願いする時の言葉"}, "examples": [{"ja": "はじめまして。グエンです。よろしくお願いします。", "vi": "Xin chào. Tôi là Nguyễn. Xin hãy giúp đỡ."}, {"ja": "今日も一日、よろしくお願いします。", "vi": "Hôm nay xin hãy chăm sóc tôi cả ngày."}], "care_example": {"ja": "朝礼で：「今日も一日、よろしくお願いします。」", "vi": "Ở cuộc họp sáng: 'Hôm nay xin hãy chăm sóc cả ngày.'"}}], "dialogue": {"title": {"ja": "介護施設の朝", "vi": "Buổi sáng ở cơ sở chăm sóc"}, "scene": {"ja": "介護スタッフが利用者さんの部屋を訪問します。", "vi": "Nhân viên chăm sóc đến thăm phòng của người được chăm sóc."}, "lines": [{"speaker": "staff", "ja": "田中さん、おはようございます。", "vi": "Tanaka san, xin chào buổi sáng."}, {"speaker": "resident", "ja": "おはよう。今日はいい天気だね。", "vi": "Chào buổi sáng. Hôm nay trời đẹp nhỉ."}, {"speaker": "staff", "ja": "はい、いい天気ですね。朝ごはんの時間ですよ。", "vi": "Vâng, trời đẹp nhỉ. Đến giờ ăn sáng rồi ạ."}, {"speaker": "resident", "ja": "ありがとう。", "vi": "Cảm ơn."}], "key_phrases": [{"ja": "体調はいかがですか？", "vi": "Sức khỏe thế nào ạ?", "note_vi": "Câu hỏi lịch sự để hỏi thăm sức khỏe"}], "cultural_note": {"ja": "日本の介護施設では、利用者さんに「さん」をつけて呼びます。", "vi": "Ở các cơ sở chăm sóc tại Nhật, luôn gọi người được chăm sóc kèm 'san' để thể hiện sự tôn trọng."}}}',
  '[{"question": {"ja": "朝、介護施設で利用者さんに最初に言う言葉は？", "vi": "Buổi sáng, từ đầu tiên nói với người được chăm sóc ở cơ sở là gì?"}, "options": [{"ja": "さようなら", "vi": "Tạm biệt"}, {"ja": "おはようございます", "vi": "Xin chào buổi sáng"}, {"ja": "こんばんは", "vi": "Xin chào buổi tối"}, {"ja": "おやすみなさい", "vi": "Chúc ngủ ngon"}], "correct": 1, "explanation": {"ja": "朝のあいさつは「おはようございます」です。利用者さんに明るく挨拶しましょう。", "vi": "Lời chào buổi sáng là \"Ohayou gozaimasu\". Hãy chào người được chăm sóc một cách vui vẻ."}, "difficulty": "easy"}, {"question": {"ja": "「よろしくお願いします」はいつ使いますか？", "vi": "\"Yoroshiku onegai shimasu\" được dùng khi nào?"}, "options": [{"ja": "別れる時", "vi": "Khi chia tay"}, {"ja": "誰かに助けを求める時", "vi": "Khi xin giúp đỡ"}, {"ja": "謝る時", "vi": "Khi xin lỗi"}, {"ja": "命令する時", "vi": "Khi ra lệnh"}], "correct": 1, "explanation": {"ja": "「よろしくお願いします」は丁寧に誰かに助けや協力を求める時に使います。", "vi": "Dùng khi xin ai đó giúp đỡ hay hợp tác một cách lịch sự."}, "difficulty": "easy"}, {"question": {"ja": "午後3時に患者さんに会った時、何と言いますか？", "vi": "Lúc 3 giờ chiều gặp bệnh nhân, nói gì ạ?"}, "options": [{"ja": "おはようございます", "vi": "Xin chào buổi sáng"}, {"ja": "こんにちは", "vi": "Xin chào ban ngày"}, {"ja": "こんばんは", "vi": "Xin chào buổi tối"}, {"ja": "おやすみなさい", "vi": "Chúc ngủ ngon"}], "correct": 1, "explanation": {"ja": "午後（昼間）は「こんにちは」を使います。", "vi": "Ban ngày/chiều dùng \"Konnichiwa\"."}, "difficulty": "medium"}, {"question": {"ja": "介護スタッフが利用者さんの名前を呼ぶ時の正しいタイトルは？", "vi": "Khi gọi tên người được chăm sóc, tiêu đề đúng là gì?"}, "options": [{"ja": "○○さん", "vi": "○○ san"}, {"ja": "○○さま", "vi": "○○ sama"}, {"ja": "○○ちゃん", "vi": "○○ chan"}, {"ja": "○○", "vi": "Chỉ tên"}], "correct": 0, "explanation": {"ja": "介護現場では「○○さん」が最も適切です。尊敬と親しみを両立させます。", "vi": "Ở cơ sở chăm sóc, \"○○ san\" là phù hợp nhất. Thể hiện tôn trọng và gần gũi."}, "difficulty": "medium"}, {"question": {"ja": "夜寝る前に利用者さんに何と言いますか？", "vi": "Trước khi ngủ ban đêm, nói với người được chăm sóc điều gì?"}, "options": [{"ja": "おはようございます", "vi": "Xin chào buổi sáng"}, {"ja": "こんばんは", "vi": "Xin chào buổi tối"}, {"ja": "さようなら", "vi": "Tạm biệt"}, {"ja": "おやすみなさい", "vi": "Chúc ngủ ngon"}], "correct": 3, "explanation": {"ja": "寝る前は「おやすみなさい」と言います。相手が良く眠れるように祈る気持ちを込めて。", "vi": "Trước khi ngủ, nói \"Oyasuminasai\". Mong rằng người đó sẽ ngủ ngon."}, "difficulty": "easy"}]',
  1,
  10
);

-- Lesson 1-2: 感謝と謝罪の表現
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 1-2: 感謝と謝罪の表現", "vi": "Unit 1-2: Lời cảm ơn và xin lỗi"}',
  '{"type": "vocabulary", "unit": 1, "lesson_number": 2, "intro": {"ja": "感謝と謝罪は介護の現場で毎日使う大切な表現です。相手を尊重する気持ちを込めて学びましょう。", "vi": "Lời cảm ơn và xin lỗi là những biểu hiện quan trọng dùng hàng ngày ở cơ sở chăm sóc. Hãy học với tấm lòng tôn trọng người khác."}, "words": [{"word": "ありがとう", "reading": "ありがとう", "kanji": null, "meaning": {"vi": "Cảm ơn", "ja": "感謝する時の言葉（普通体）"}, "examples": [{"ja": "ありがとう。助かるよ。", "vi": "Cảm ơn. Tôi rất cảm ơn."}, {"ja": "毎日ありがとう。", "vi": "Cảm ơn hàng ngày."}], "care_example": {"ja": "利用者さんが感謝した時：「ありがとうございます。こちらこそありがとうございます。」", "vi": "Khi người được chăm sóc cảm ơn: 'Arigatou gozaimasu. Kochira koso arigatou gozaimasu.'"}}, {"word": "ありがとうございます", "reading": "ありがとうございます", "kanji": null, "meaning": {"vi": "Cảm ơn (lịch sự)", "ja": "感謝する時の丁寧な言葉"}, "examples": [{"ja": "お手伝いいただき、ありがとうございます。", "vi": "Cảm ơn bạn đã giúp đỡ tôi."}, {"ja": "毎日のご指導、ありがとうございます。", "vi": "Cảm ơn hướng dẫn hàng ngày."}], "care_example": {"ja": "利用者さんがお礼を言った時：「ありがとうございます。」と返礼する", "vi": "Khi người được chăm sóc cảm ơn, đáp lại: 'Arigatou gozaimasu.'"}}, {"word": "すみません", "reading": "すみません", "kanji": null, "meaning": {"vi": "Xin lỗi / Xin phép", "ja": "申し訳ないと言う時、また誰かに何かを頼む時"}, "examples": [{"ja": "すみません。少し手伝ってもらえますか？", "vi": "Xin lỗi. Bạn có thể giúp tôi một chút không?"}, {"ja": "すみませんが、ここに座ってください。", "vi": "Xin lỗi, hãy ngồi ở đây."}], "care_example": {"ja": "利用者さんに何かを頼む時：「すみませんが、ちょっと移動していただけますか？」", "vi": "Khi yêu cầu người được chăm sóc: 'Xin lỗi, bạn có thể di chuyển một chút được không?'"}}, {"word": "申し訳ありません", "reading": "もうしわけありません", "kanji": "申し訳", "meaning": {"vi": "Xin lỗi (rất lịch sự)", "ja": "本当に申し訳ない時の最も丁寧な言葉"}, "examples": [{"ja": "申し訳ありません。遅刻してしまいました。", "vi": "Xin lỗi. Tôi đã đi muộn."}, {"ja": "申し訳ございません。ご不便をおかけして。", "vi": "Xin lỗi rất nhiều. Tôi đã gây bất tiện cho bạn."}], "care_example": {"ja": "深夜に利用者さんを起こした時：「申し訳ありません。お薬の時間になってしまいました。」", "vi": "Khi phải đánh thức người được chăm sóc vào đêm: 'Xin lỗi. Đã đến giờ uống thuốc rồi.'"}}], "dialogue": {"title": {"ja": "援助の感謝", "vi": "Cảm ơn vì sự giúp đỡ"}, "scene": {"ja": "利用者さんが介護スタッフの力を借りて、何かを成し遂げた時", "vi": "Người được chăm sóc nhờ sự giúp đỡ của nhân viên để hoàn thành điều gì đó"}, "lines": [{"speaker": "resident", "ja": "ありがとう。君のおかげでできたよ。", "vi": "Cảm ơn. Nhờ bạn mà tôi được làm."}, {"speaker": "staff", "ja": "いいえ、こちらこそありがとうございます。", "vi": "Không đâu, cảm ơn bạn."}, {"speaker": "resident", "ja": "毎日、本当にありがとう。", "vi": "Cảm ơn bạn hàng ngày."}, {"speaker": "staff", "ja": "ありがとうございます。こちらも楽しいです。", "vi": "Cảm ơn bạn. Tôi cũng cảm thấy vui."}], "key_phrases": [{"ja": "こちらこそありがとうございます", "vi": "Cảm ơn bạn (trả lời cảm ơn)", "note_vi": "Câu trả lời khi nhận được lời cảm ơn"}], "cultural_note": {"ja": "日本では相手が感謝したら、「こちらこそありがとうございます」と返すのが礼儀です。", "vi": "Ở Nhật Bản, khi ai đó cảm ơn bạn, lịch sự phải đáp lại bằng 'Kochira koso arigatou gozaimasu'."}}}}',
  '[{"question": {"ja": "友人に感謝する時の最も普通な言い方は？", "vi": "Cảm ơn bạn bè, cách nói phổ thông nhất là?"}, "options": [{"ja": "ありがとう", "vi": "Arigatou"}, {"ja": "申し訳ありません", "vi": "Moushiwake arimasen"}, {"ja": "すみません", "vi": "Sumimasen"}, {"ja": "ありがとうございます", "vi": "Arigatou gozaimasu"}], "correct": 0, "explanation": {"ja": "友人や親戚には「ありがとう」で大丈夫です。", "vi": "Với bạn bè hay gia đình, nói \"Arigatou\" là được."}, "difficulty": "easy"}, {"question": {"ja": "介護施設で利用者さんに何かをお願いする時は？", "vi": "Khi yêu cầu người được chăm sóc làm gì ở cơ sở, nói:"}, "options": [{"ja": "すみませんが〜できますか？", "vi": "Sumimasen ga ~ dekimasu ka?"}, {"ja": "ありがとうございます", "vi": "Arigatou gozaimasu"}, {"ja": "申し訳ありません", "vi": "Moushiwake arimasen"}, {"ja": "よろしくお願いします", "vi": "Yoroshiku onegai shimasu"}], "correct": 0, "explanation": {"ja": "「すみませんが」で丁寧に何かをお願いします。", "vi": "Dùng \"Sumimasen ga\" để yêu cầu điều gì đó một cách lịch sự."}, "difficulty": "medium"}, {"question": {"ja": "本当に申し訳ない時の最も丁寧な言い方は？", "vi": "Cách nói lịch sự nhất khi thực sự xin lỗi:"}, "options": [{"ja": "ごめんなさい", "vi": "Gomennasai"}, {"ja": "申し訳ありません", "vi": "Moushiwake arimasen"}, {"ja": "すみません", "vi": "Sumimasen"}, {"ja": "申し訳ございません", "vi": "Moushiwake gozaimasen"}], "correct": 1, "explanation": {"ja": "「申し訳ありません」は「申し訳ございません」より少し普通で、でも十分に丁寧です。", "vi": "\"Moushiwake arimasen\" là rất lịch sự và thích hợp."}, "difficulty": "medium"}, {"question": {"ja": "介護スタッフが利用者さんの感謝に対して、何と返していますか？", "vi": "Nhân viên chăm sóc trả lời cảm ơn của người được chăm sóc như thế nào?"}, "options": [{"ja": "申し訳ございません", "vi": "Moushiwake gozaimasen"}, {"ja": "こちらこそありがとうございます", "vi": "Kochira koso arigatou gozaimasu"}, {"ja": "すみません", "vi": "Sumimasen"}, {"ja": "ごめんなさい", "vi": "Gomennasai"}], "correct": 1, "explanation": {"ja": "「こちらこそありがとうございます」は相手の感謝に対しての返礼です。", "vi": "\"Kochira koso arigatou gozaimasu\" là câu trả lời khi nhận lời cảm ơn."}, "difficulty": "hard"}, {"question": {"ja": "夜間に利用者さんを起こす時、正しい言い方は？", "vi": "Khi phải đánh thức người được chăm sóc vào ban đêm, nói:"}, "options": [{"ja": "すぐに起きてください", "vi": "Thức dậy ngay"}, {"ja": "申し訳ありません。お薬の時間になってしまいました。", "vi": "Xin lỗi. Đã đến giờ uống thuốc."}, {"ja": "ありがとうございます", "vi": "Cảm ơn"}, {"ja": "おはようございます", "vi": "Xin chào buổi sáng"}], "correct": 1, "explanation": {"ja": "利用者さんの睡眠を妨害するので、先に申し訳なさを表します。", "vi": "Vì phải làm gián đoạn giấc ngủ, trước tiên phải xin lỗi."}, "difficulty": "hard"}]',
  2,
  10
);

-- Lesson 1-3: 肯定と否定の表現
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 1-3: 肯定と否定の表現", "vi": "Unit 1-3: Cách nói có và không"}',
  '{"type": "vocabulary", "unit": 1, "lesson_number": 3, "intro": {"ja": "はい、いいえという返答は日本語の基本です。質問に正しく答える練習をしましょう。", "vi": "Trả lời \"Có\" và \"Không\" là cơ bản của tiếng Nhật. Hãy luyện trả lời câu hỏi chính xác."}, "words": [{"word": "はい", "reading": "はい", "kanji": null, "meaning": {"vi": "Có, vâng", "ja": "肯定の返事"}, "examples": [{"ja": "これはいいですか？はい、いいです。", "vi": "Cái này tốt không? Vâng, tốt lắm."}, {"ja": "明日も来られますか？はい、来ます。", "vi": "Ngày mai bạn có thể đến không? Vâng, tôi sẽ đến."}], "care_example": {"ja": "利用者さんへの確認：「体調はいいですか？」「はい、大丈夫です。」", "vi": "Xác nhận với người được chăm sóc: 'Sức khỏe tốt không?' 'Vâng, tôi khỏe.'"}}]}',
  '[{"question": {"ja": "肯定の返事は？", "vi": "Câu trả lời có/vâng là:"}, "options": [{"ja": "いいえ", "vi": "Không"}, {"ja": "はい", "vi": "Vâng"}, {"ja": "わかりません", "vi": "Không hiểu"}, {"ja": "多分", "vi": "Có lẽ"}], "correct": 1, "explanation": {"ja": "「はい」は肯定の返事です。", "vi": "\"Hai\" là câu trả lời có/vâng."}, "difficulty": "easy"}, {"question": {"ja": "否定の返事は？", "vi": "Câu trả lời không/phủ nhận là:"}, "options": [{"ja": "はい", "vi": "Vâng"}, {"ja": "いいえ", "vi": "Không"}, {"ja": "ありがとう", "vi": "Cảm ơn"}, {"ja": "すみません", "vi": "Xin lỗi"}], "correct": 1, "explanation": {"ja": "「いいえ」は否定の返事です。", "vi": "\"Iie\" là câu trả lời không/phủ nhận."}, "difficulty": "easy"}, {"question": {"ja": "「このお薬を飲みますか？」と聞かれた時、飲む場合の返事は？", "vi": "Được hỏi \"Bạn có uống thuốc này không?\" khi uống, trả lời:"}, "options": [{"ja": "いいえ", "vi": "Không"}, {"ja": "はい、飲みます", "vi": "Vâng, tôi sẽ uống"}, {"ja": "分かりません", "vi": "Không hiểu"}, {"ja": "ありがとう", "vi": "Cảm ơn"}], "correct": 1, "explanation": {"ja": "飲む場合は「はい、飲みます」と返します。", "vi": "Khi uống, trả lời \"Hai, nomimasu\"."}, "difficulty": "medium"}, {"question": {"ja": "介護スタッフが「明日、来られますか？」と聞いた時、来ない場合の返事は？", "vi": "Nhân viên hỏi \"Ngày mai bạn có thể đến không?\" nếu không đến, trả lời:"}, "options": [{"ja": "はい、来ます", "vi": "Vâng, tôi sẽ đến"}, {"ja": "いいえ、来られません", "vi": "Không, tôi không thể đến"}, {"ja": "わかりません", "vi": "Không hiểu"}, {"ja": "ありがとうございます", "vi": "Cảm ơn"}], "correct": 1, "explanation": {"ja": "来ない場合は「いいえ、来られません」と返します。", "vi": "Khi không thể đến, trả lời \"Iie, koraremasen\"."}, "difficulty": "medium"}, {"question": {"ja": "患者さんが「このご飯、美味しいですか？」と聞いた時、「美味しくない」場合、何と答えますか？", "vi": "Bệnh nhân hỏi \"Cơm này ngon không?\" nếu không ngon, trả lời gì?"}, "options": [{"ja": "はい、美味しいです", "vi": "Vâng, rất ngon"}, {"ja": "いいえ、あまり美味しくないです", "vi": "Không, không ngon lắm"}, {"ja": "わかりません", "vi": "Không hiểu"}, {"ja": "食べません", "vi": "Tôi không ăn"}], "correct": 1, "explanation": {"ja": "正直に「いいえ、あまり美味しくないです」と答えるのは失礼なので、「いいえ、様々なお味があります」など、丁寧に答えるべきです。", "vi": "Tuy nhiên, để lịch sự, nên trả lời một cách dễ dàng hơn như \"Còn tùy hơi, có nhiều vị khác nhau.\" Tuy nhiên, trong bối cảnh này, trả lời \"Iie\" là để từ chối.\"}, "difficulty": "hard"}]',
  3,
  10
);

-- Lesson 1-4: 質問と確認の表現
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 1-4: 質問と確認の表現", "vi": "Unit 1-4: Cách hỏi và xác nhận"}',
  '{"type": "vocabulary", "unit": 1, "lesson_number": 4, "intro": {"ja": "介護の現場では、利用者さんの状態を常に確認する必要があります。良い質問の仕方を学びましょう。", "vi": "Ở cơ sở chăm sóc, luôn cần xác nhận tình trạng của người được chăm sóc. Hãy học cách hỏi tốt."}, "words": [{"word": "どうですか？", "reading": "どうですか", "kanji": null, "meaning": {"vi": "Thế nào?/Tình trạng như thế nào?", "ja": "相手の状態や気分を聞く時"}, "examples": [{"ja": "お体の調子はどうですか？", "vi": "Sức khỏe thế nào?"}, {"ja": "今日の気分はどうですか？", "vi": "Tâm trạng hôm nay thế nào?"}], "care_example": {"ja": "朝、利用者さんの部屋に入った時：「おはようございます。今朝のお体の調子はどうですか？」", "vi": "Vào phòng người được chăm sóc buổi sáng: \"Ohayou gozaimasu. Taichou wa kyou dou desu ka?\""}}]}',
  '[{"question": {"ja": "利用者さんの状態を聞きたい時の質問は？", "vi": "Để hỏi tình trạng của người được chăm sóc:"}, "options": [{"ja": "何をしていますか？", "vi": "Bạn đang làm gì?"}, {"ja": "どうですか？", "vi": "Thế nào?"}, {"ja": "誰ですか？", "vi": "Bạn là ai?"}, {"ja": "どこですか？", "vi": "Ở đâu?"}], "correct": 1, "explanation": {"ja": "「どうですか？」は相手の状態や気分を聞く時に使う質問です。", "vi": "\"Dou desu ka?\" được dùng để hỏi tình trạng hoặc cảm xúc."}, "difficulty": "easy"}, {"question": {"ja": "「いかがですか？」と「どうですか？」の違いは？", "vi": "Sự khác nhau giữa \"Ikaga desu ka?\" và \"Dou desu ka?\" là gì?"}, "options": [{"ja": "意味は同じですが、「いかがですか」の方がより丁寧です", "vi": "Nghĩa giống nhau, nhưng \"Ikaga desu ka?\" lịch sự hơn"}, {"ja": "「いかがですか」は否定、「どうですか」は肯定です", "vi": "\"Ikaga\" là phủ nhận, \"Dou\" là khẳng định"}, {"ja": "「どうですか」だけが質問です", "vi": "Chỉ \"Dou desu ka?\" là câu hỏi"}, {"ja": "違いはありません", "vi": "Không có sự khác nhau"}], "correct": 0, "explanation": {"ja": "意味は同じですが、「いかがですか」の方がより丁寧で敬意を示します。介護現場では両方使えますが、より丁寧にしたい時は「いかがですか」を使います。", "vi": "Cả hai có nghĩa giống nhau, nhưng \"Ikaga desu ka?\" là lịch sự và tôn trọng hơn. Ở cơ sở chăm sóc, cả hai đều dùng được, nhưng nếu muốn lịch sự hơn thì dùng \"Ikaga desu ka?\"."}, "difficulty": "medium"}, {"question": {"ja": "患者さんに「今朝の体調はいかがですか？」と聞いた時、良い返事をしてください。", "vi": "Khi hỏi người được chăm sóc \"Sức khỏe buổi sáng thế nào?\" Trả lời tốt:"}, "options": [{"ja": "いいえ", "vi": "Không"}, {"ja": "わかりません", "vi": "Không hiểu"}, {"ja": "今朝は体調が良いです", "vi": "Buổi sáng hôm nay tôi khỏe"}, {"ja": "質問にお答えできません", "vi": "Tôi không thể trả lời"}], "correct": 2, "explanation": {"ja": "「今朝は体調が良いです」など、具体的に答えるのが良いです。", "vi": "Trả lời cụ thể như \"Buổi sáng hôm nay tôi khỏe\" là tốt."}, "difficulty": "medium"}, {"question": {"ja": "介護スタッフが利用者さんに「昨夜よく眠れましたか？」と聞きたい場合、正しい言い方は？", "vi": "Khi nhân viên muốn hỏi người được chăm sóc \"Đêm qua ngủ ngon không?\" cách nói đúng:"}, "options": [{"ja": "昨夜眠りましたか？", "vi": "Đêm qua bạn ngủ không?"}, {"ja": "昨夜よく眠れましたか？", "vi": "Đêm qua bạn ngủ ngon không?"}, {"ja": "眠いですか？", "vi": "Bạn có buồn ngủ không?"}, {"ja": "いつ寝ましたか？", "vi": "Bạn ngủ khi nào?"}], "correct": 1, "explanation": {"ja": "「よく眠れた」は「質の良い睡眠ができた」という意味で、介護現場で頻繁に使う表現です。", "vi": "\"Yoku nemureru\" nghĩa là ngủ ngon/được ngủ tốt, và đây là cách nói thường dùng ở cơ sở chăm sóc."}, "difficulty": "hard"}, {"question": {"ja": "患者さんがシャワーを浴びた後、「いかがでしたか？」と聞いた時、最良の返事は？", "vi": "Sau khi người được chăm sóc tắm, khi hỏi \"Thế nào?\" trả lời tốt nhất:"}, "options": [{"ja": "わかりません", "vi": "Không hiểu"}, {"ja": "いいえ", "vi": "Không"}, {"ja": "気分が良くなりました", "vi": "Tôi cảm thấy tốt hơn"}, {"ja": "シャワーを浴びました", "vi": "Tôi đã tắm"}], "correct": 2, "explanation": {"ja": "「いかがでしたか？」への返事として、「気分が良くなりました」など、具体的な感想を答えるのが自然です。", "vi": "Trả lời \"Ikaga deshita ka?\" bằng cảm xúc cụ thể như \"Tôi cảm thấy tốt hơn\" là tự nhiên nhất."}, "difficulty": "hard"}]',
  4,
  10
);

-- ================================
-- Unit 2: 数字・時間・曜日（Lesson 5-8）
-- ================================

-- Lesson 2-1: 数字と基本的な数詞
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 2-1: 数字と基本的な数詞", "vi": "Unit 2-1: Số đếm và từ đếm cơ bản"}',
  '{"type": "vocabulary", "unit": 2, "lesson_number": 1, "intro": {"ja": "数字は日本語学習の基本です。時間、薬の量、患者さんの年齢など、介護現場で毎日必要な表現です。", "vi": "Số đếm là cơ bản của học tiếng Nhật. Thời gian, liều lượng thuốc, tuổi của người được chăm sóc... cần thiết hàng ngày ở cơ sở."}, "words": [{"word": "一（いち）", "reading": "いち", "kanji": "1", "meaning": {"vi": "Một", "ja": "基本的な数字"}, "examples": [{"ja": "これは一つです。", "vi": "Cái này là một."}, {"ja": "一番最初。", "vi": "Cái đầu tiên."}], "care_example": {"ja": "薬の量：「この薬は一日に一回飲んでください。」", "vi": "Liều lượng thuốc: \"Hãy uống thuốc này một lần một ngày.\""}}]}',
  '[{"question": {"ja": "\"1\"を日本語で言うと？", "vi": "Nói \"1\" bằng tiếng Nhật:"}, "options": [{"ja": "ゼロ", "vi": "Zero"}, {"ja": "いち", "vi": "Ichi"}, {"ja": "に", "vi": "Ni"}, {"ja": "さん", "vi": "San"}], "correct": 1, "explanation": {"ja": "\"1\"は\"いち\"です。", "vi": "\"1\" là \"ichi\"."}, "difficulty": "easy"}, {"question": {"ja": "患者さんに薬を渡す時、「一日に何回飲みますか？」の返事として正しいのは？", "vi": "Khi đưa thuốc cho người được chăm sóc, trả lời \"Ngày nào uống mấy lần?\" đúng nhất:"}, "options": [{"ja": "二回です", "vi": "Hai lần"}, {"ja": "一回です", "vi": "Một lần"}, {"ja": "三回です", "vi": "Ba lần"}, {"ja": "四回です", "vi": "Bốn lần"}], "correct": 1, "explanation": {"ja": "通常、薬は一日に一回から三回飲みます。例として「一回です」と答えることができます。", "vi": "Thông thường, thuốc uống từ một đến ba lần một ngày. Ví dụ, có thể trả lời \"Một lần\"."}, "difficulty": "medium"}, {"question": {"ja": "患者さんの年齢が72歳の場合、「何歳ですか？」への返事は？", "vi": "Nếu tuổi người được chăm sóc là 72 tuổi, trả lời \"Bao nhiêu tuổi?\"："}, "options": [{"ja": "73です", "vi": "73 tuổi"}, {"ja": "71です", "vi": "71 tuổi"}, {"ja": "72です", "vi": "72 tuổi"}, {"ja": "70です", "vi": "70 tuổi"}], "correct": 2, "explanation": {"ja": "72歳なので「72です」と答えます。\"さい\"は年齢の単位です。", "vi": "Vì 72 tuổi nên trả lời \"72 desu\". \"Sai\" là đơn vị tuổi."}, "difficulty": "easy"}, {"question": {"ja": "介護スタッフが「これは三錠です」と言った場合、意味は？", "vi": "Khi nhân viên nói \"Kore wa san jou desu\" (Cái này là ba viên), nghĩa là:"}, "options": [{"ja": "これは三つです", "vi": "Cái này là ba cái"}, {"ja": "これは三回です", "vi": "Cái này là ba lần"}, {"ja": "これは三日です", "vi": "Cái này là ba ngày"}, {"ja": "これは三年です", "vi": "Cái này là ba năm"}], "correct": 0, "explanation": {"ja": "\"錠\"（じょう）は薬の数を数える単位です。\"三錠\"は\"三つ\"（３つ）の薬を意味します。", "vi": "\"Jou\" là từ đếm cho viên thuốc. \"San jou\" có nghĩa là ba viên thuốc."}, "difficulty": "hard"}, {"question": {"ja": "患者さんに「朝と夜の二回飲んでください」と言いたい場合、正しい言い方は？", "vi": "Muốn nói với người được chăm sóc \"Uống buổi sáng và buổi tối hai lần\" cách nói đúng:"}, "options": [{"ja": "朝と夜に一回飲んでください", "vi": "Uống buổi sáng và buổi tối một lần"}, {"ja": "朝と夜の二回飲んでください", "vi": "Uống buổi sáng và buổi tối hai lần"}, {"ja": "朝と夜で三回飲んでください", "vi": "Uống buổi sáng và buổi tối ba lần"}, {"ja": "朝と夜は四回飲んでください", "vi": "Uống buổi sáng và buổi tối bốn lần"}], "correct": 1, "explanation": {"ja": "「朝と夜の二回」は朝1回、夜1回の計２回を意味します。", "vi": "\"Asa to yoru no nikai\" có nghĩa là uống buổi sáng 1 lần, buổi tối 1 lần, tổng cộng 2 lần."}, "difficulty": "hard"}]',
  5,
  10
);

-- Lesson 2-2: 時間の表現
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 2-2: 時間の表現", "vi": "Unit 2-2: Cách nói thời gian"}',
  '{"type": "vocabulary", "unit": 2, "lesson_number": 2, "intro": {"ja": "介護施設では時間管理が非常に大切です。食事時間、服薬時間、ケアの時間、全て正確に伝える必要があります。", "vi": "Ở cơ sở chăm sóc, quản lý thời gian rất quan trọng. Giờ ăn, giờ uống thuốc, giờ chăm sóc, tất cả phải nói chính xác."}, "words": [{"word": "八時（はちじ）", "reading": "はちじ", "kanji": "8時", "meaning": {"vi": "8 giờ", "ja": "午前または午後の8時"}, "examples": [{"ja": "朝は八時に起きます。", "vi": "Sáng tôi thức dậy lúc 8 giờ."}, {"ja": "八時に朝食の時間です。", "vi": "8 giờ là giờ ăn sáng."}], "care_example": {"ja": "朝食の時間：「○○さん、八時になりました。朝ごはんの時間です。」", "vi": "Giờ ăn sáng: \"○○ san, hachi ji ni narimashita. Asagohan no jikan desu.\""}}]}',
  '[{"question": {"ja": "\"14時\"（午後2時）を日本語で言うと？", "vi": "Nói \"14時\" (2 giờ chiều) bằng tiếng Nhật:"}, "options": [{"ja": "十四時です", "vi": "14 giờ"}, {"ja": "二時です", "vi": "2 giờ"}, {"ja": "午後二時です", "vi": "2 giờ chiều"}, {"ja": "十四時か午後二時です", "vi": "14 giờ hoặc 2 giờ chiều"}], "correct": 3, "explanation": {"ja": "\"14時\"は\"十四時\"または\"午後二時\"と言えます。どちらでも大丈夫です。", "vi": "\"14時\" có thể nói là \"Juu yon ji\" hoặc \"Gogo ni ji\". Cả hai đều được."}, "difficulty": "medium"}, {"question": {"ja": "「朝食は何時ですか？」と聞かれた時、朝食が8時の場合の返事は？", "vi": "Được hỏi \"Ăn sáng lúc mấy giờ?\" nếu ăn sáng lúc 8 giờ, trả lời:"}, "options": [{"ja": "朝食は八時です", "vi": "Ăn sáng lúc 8 giờ"}, {"ja": "朝食は九時です", "vi": "Ăn sáng lúc 9 giờ"}, {"ja": "朝食は七時です", "vi": "Ăn sáng lúc 7 giờ"}, {"ja": "朝食は午後八時です", "vi": "Ăn sáng lúc 8 giờ chiều"}], "correct": 0, "explanation": {"ja": "朝食が8時なので「朝食は八時です」と答えます。", "vi": "Vì ăn sáng lúc 8 giờ nên trả lời \"Asagohan wa hachi ji desu\"."}, "difficulty": "easy"}, {"question": {"ja": "患者さんに「服薬は朝七時、昼十二時、夜六時です」と説明する場合、正しいですか？", "vi": "Khi giải thích cho người được chăm sóc \"Uống thuốc 7 giờ sáng, 12 giờ trưa, 6 giờ tối\" có đúng không?"}, "options": [{"ja": "はい、正しいです", "vi": "Vâng, đúng"}, {"ja": "いいえ、間違っています。\"午前7時\"と言うべきです", "vi": "Không, sai. Nên nói \"7 giờ sáng\" (am)"}, {"ja": "いいえ、\"朝七時\"ではなく\"夜七時\"と言うべきです", "vi": "Không, nên nói \"7 giờ tối\" không phải \"7 giờ sáng\""}, {"ja": "いいえ、時刻を違う順序で説明すべきです", "vi": "Không, nên giải thích theo thứ tự thời gian khác"}], "correct": 0, "explanation": {"ja": "朝七時、昼十二時、夜六時の順序と時刻は正しいです。介護の現場では通常このような時刻設定があります。", "vi": "Thứ tự 7 giờ sáng, 12 giờ trưa, 6 giờ tối là đúng. Đó là thời gian uống thuốc thông thường ở cơ sở chăm sóc."}, "difficulty": "medium"}, {"question": {"ja": "夜中の2時に患者さんを起こしたい場合、最も適切な時刻の呼び方は？", "vi": "Muốn đánh thức người được chăm sóc lúc 2 giờ sáng sớm (ban đêm), cách nói thích hợp nhất:"}, "options": [{"ja": "二時です", "vi": "2 giờ"}, {"ja": "午後二時です", "vi": "2 giờ chiều"}, {"ja": "午前二時です", "vi": "2 giờ sáng"}, {"ja": "夜中の二時です", "vi": "2 giờ đêm"}], "correct": 2, "explanation": {"ja": "夜中の2時は\"午前二時\"と言います。正確に患者さんに伝える必要があります。", "vi": "2 giờ sáng sớm (ban đêm) gọi là \"Gogo ni ji\" (2 giờ chiều) hoặc \"Gozen ni ji\" (2 giờ sáng). Vì là lúc sáng nên dùng \"Gozen ni ji\" để chính xác."}, "difficulty": "hard"}, {"question": {"ja": "介護スタッフが利用者さんに「昼食は十二時です」と伝えた場合、何時にごはんを食べることを意味しますか？", "vi": "Khi nhân viên nói với người được chăm sóc \"Ăn trưa lúc 12 giờ\", có nghĩa ăn lúc mấy giờ?"}, "options": [{"ja": "午前12時（夜中）です", "vi": "12 giờ sáng (ban đêm)"}, {"ja": "午後12時（昼間）です", "vi": "12 giờ trưa (ban ngày)"}, {"ja": "午後1時です", "vi": "1 giờ chiều"}, {"ja": "午前1時です", "vi": "1 giờ sáng"}], "correct": 1, "explanation": {"ja": "昼食は昼間（午後）なので、十二時は午後12時を意味します。これは日本語では正午（しょうご）の時刻です。", "vi": "Ăn trưa là vào ban ngày nên 12 giờ có nghĩa là 12 giờ trưa. Đây gọi là \"Shoogo\" (giờ trưa) ở Nhật."}, "difficulty": "hard"}]',
  6,
  10
);

-- Lesson 2-3: 曜日
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 2-3: 曜日", "vi": "Unit 2-3: Các ngày trong tuần"}',
  '{"type": "vocabulary", "unit": 2, "lesson_number": 3, "intro": {"ja": "曜日は週間スケジュールを説明する時に必須です。「月曜日は入浴の日です」など、介護計画を患者さんに説明します。", "vi": "Tên ngày trong tuần rất cần thiết để giải thích lịch trình hàng tuần. \"Thứ Hai là ngày tắm\" v.v., giải thích kế hoạch chăm sóc cho người được chăm sóc."}, "words": [{"word": "月曜日（げつようび）", "reading": "げつようび", "kanji": "月曜日", "meaning": {"vi": "Thứ Hai", "ja": "一週間で最初の営業日"}, "examples": [{"ja": "月曜日は朝の体操があります。", "vi": "Thứ Hai có bài tập sáng."}, {"ja": "毎週月曜日に散歩に行きます。", "vi": "Mỗi tuần thứ Hai chúng ta đi bộ."}], "care_example": {"ja": "週間スケジュール説明：「月曜日は入浴の日です。」", "vi": "Giải thích lịch trình: \"Thứ Hai là ngày tắm.\""}}]}',
  '[{"question": {"ja": "\"月曜日\"を略して言うと？", "vi": "Viết tắt \"月曜日\" (Thứ Hai) thành:"}, "options": [{"ja": "月曜", "vi": "Getsuyou"}, {"ja": "月日", "vi": "Tsukinichi"}, {"ja": "げつ", "vi": "Getsu"}, {"ja": "週月", "vi": "Shuugetsu"}], "correct": 0, "explanation": {"ja": "\"月曜日\"は\"月曜\"と略されます。", "vi": "\"Getsuyoubi\" được viết tắt thành \"Getsuyou\"."}, "difficulty": "easy"}, {"question": {"ja": "「水曜日は何をする日ですか？」と聞かれた場合、介護の観点から考えると？", "vi": "Khi được hỏi \"Thứ Tư làm gì?\" từ góc độ chăm sóc:"}, "options": [{"ja": "水曜日は特に何もしない日です", "vi": "Thứ Tư không làm gì đặc biệt"}, {"ja": "水曜日はお風呂の日です", "vi": "Thứ Tư là ngày tắm"}, {"ja": "水曜日は運動の日です", "vi": "Thứ Tư là ngày tập thể dục"}, {"ja": "介護施設によって異なります", "vi": "Tùy theo cơ sở chăm sóc"}], "correct": 3, "explanation": {"ja": "介護施設のスケジュールは様々です。各施設で異なる活動計画があります。", "vi": "Lịch trình ở mỗi cơ sở chăm sóc khác nhau. Mỗi cơ sở có kế hoạch hoạt động riêng."}, "difficulty": "medium"}, {"question": {"ja": "患者さんに「毎週金曜日に理髪があります」と説明する場合、正しいですか？", "vi": "Giải thích cho người được chăm sóc \"Mỗi tuần thứ Sáu có cắt tóc\" có đúng không?"}, "options": [{"ja": "はい、正しいです", "vi": "Vâng, đúng"}, {"ja": "いいえ、\"毎週\"ではなく\"毎日\"と言うべきです", "vi": "Không, nên nói \"mỗi ngày\" không phải \"mỗi tuần\""}, {"ja": "いいえ、\"金曜日\"ではなく\"土曜日\"と言うべきです", "vi": "Không, nên nói \"Thứ Bảy\" không phải \"Thứ Sáu\""}, {"ja": "いいえ、曜日の説明は不要です", "vi": "Không, không cần giải thích ngày"}], "correct": 0, "explanation": {"ja": "\"毎週金曜日に理髪があります\"は正しい説明です。介護施設では定期的に散髪をする習慣があります。", "vi": "Giải thích \"Mỗi tuần thứ Sáu có cắt tóc\" là đúng. Ở cơ sở chăm sóc, có thường lệ cắt tóc định kỳ."}, "difficulty": "medium"}, {"question": {"ja": "日本の一週間は何曜日から始まりますか？", "vi": "Tuần ở Nhật Bản bắt đầu từ ngày nào?"}, "options": [{"ja": "日曜日から始まります", "vi": "Bắt đầu từ Chủ Nhật"}, {"ja": "月曜日から始まります", "vi": "Bắt đầu từ Thứ Hai"}, {"ja": "土曜日から始まります", "vi": "Bắt đầu từ Thứ Bảy"}, {"ja": "水曜日から始まります", "vi": "Bắt đầu từ Thứ Tư"}], "correct": 0, "explanation": {"ja": "日本では日曜日から週が始まります。ただし、多くのカレンダーや職場では月曜日を週の始まりとして扱う場合もあります。", "vi": "Ở Nhật Bản, tuần bắt đầu từ Chủ Nhật. Tuy nhiên, ở một số lịch hoặc nơi làm việc, có thể coi Thứ Hai là ngày bắt đầu tuần."}, "difficulty": "medium"}, {"question": {"ja": "「毎週日曜日に家族が訪ねてきます」と言う場合、何曜日に訪問ですか？", "vi": "Khi nói \"Mỗi tuần Chủ Nhật gia đình đến thăm\", đó là ngày nào?"}, "options": [{"ja": "月曜日です", "vi": "Thứ Hai"}, {"ja": "日曜日です", "vi": "Chủ Nhật"}, {"ja": "土曜日です", "vi": "Thứ Bảy"}, {"ja": "金曜日です", "vi": "Thứ Sáu"}], "correct": 1, "explanation": {"ja": "\"毎週日曜日\"は毎週の日曜日を意味します。つまり、日曜日に訪問があります。", "vi": "\"Maishuuk Nichiyoubi\" có nghĩa là mỗi tuần Chủ Nhật. Tức là Chủ Nhật là ngày thăm."}, "difficulty": "easy"}]',
  7,
  10
);

-- Lesson 2-4: 月と季節
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 2-4: 月と季節", "vi": "Unit 2-4: Các tháng và mùa"}',
  '{"type": "vocabulary", "unit": 2, "lesson_number": 4, "intro": {"ja": "月と季節は季節特有の行事や感染症対策を説明する時に大切です。「冬は風邪に注意が必要です」など、季節に応じた介護情報を共有します。", "vi": "Tháng và mùa rất quan trọng để giải thích các hoạt động đặc trưng theo mùa và biện pháp phòng chống bệnh. Chia sẻ thông tin chăm sóc theo mùa, chẳng hạn \"Mùa đông phải cẩn thận với cảm lạnh\"."}, "words": [{"word": "春（はる）", "reading": "はる", "kanji": "春", "meaning": {"vi": "Mùa xuân", "ja": "年の最初の季節（3月〜5月）"}, "examples": [{"ja": "春は新しい始まりの季節です。", "vi": "Mùa xuân là mùa bắt đầu mới."}, {"ja": "春は花が咲きます。", "vi": "Mùa xuân hoa nở."}], "care_example": {"ja": "季節ケア：「春になりました。新しい季節が来ましたね。」", "vi": "Chăm sóc theo mùa: \"Đã vào mùa xuân. Mùa mới đã đến nhỉ.\""}}, {"word": "夏（なつ）", "reading": "なつ", "kanji": "夏", "meaning": {"vi": "Mùa hè", "ja": "最も暑い季節（6月〜8月）"}, "examples": [{"ja": "夏は熱中症に注意が必要です。", "vi": "Mùa hè phải cảnh báo đột quỵ do nắng."}, {"ja": "夏はたくさん水を飲みましょう。", "vi": "Mùa hè hãy uống nhiều nước."}], "care_example": {"ja": "健康管理：「夏は脱水症状に気をつけます。」", "vi": "Quản lý sức khỏe: \"Mùa hè phải cảnh báo mất nước.\""}}, {"word": "秋（あき）", "reading": "あき", "kanji": "秋", "meaning": {"vi": "Mùa thu", "ja": "涼しくなる季節（9月〜11月）"}, "examples": [{"ja": "秋は運動会の季節です。", "vi": "Mùa thu là mùa hội thao."}, {"ja": "秋は食べ物がおいしいです。", "vi": "Mùa thu đồ ăn ngon lắm."}], "care_example": {"ja": "季節行事：「秋は文化祭があります。」", "vi": "Hoạt động mùa: \"Mùa thu có lễ hội văn hóa.\""}}]}',
  '[{"question": {"ja": "日本の一月は何月ですか？", "vi": "Tháng Giêng ở Nhật Bản là tháng nào?"}, "options": [{"ja": "12月", "vi": "Tháng 12"}, {"ja": "1月", "vi": "Tháng 1"}, {"ja": "2月", "vi": "Tháng 2"}, {"ja": "3月", "vi": "Tháng 3"}], "correct": 1, "explanation": {"ja": "一月は１月です。", "vi": "\"Ichigatsu\" là tháng 1."}, "difficulty": "easy"}, {"question": {"ja": "春はいつですか？", "vi": "Mùa xuân là khi nào?"}, "options": [{"ja": "12月から2月", "vi": "Tháng 12-2"}, {"ja": "3月から5月", "vi": "Tháng 3-5"}, {"ja": "6月から8月", "vi": "Tháng 6-8"}, {"ja": "9月から11月", "vi": "Tháng 9-11"}], "correct": 1, "explanation": {"ja": "春は3月から5月（3月、4月、5月）です。", "vi": "Mùa xuân từ tháng 3 đến 5 (Tháng 3, 4, 5)."}, "difficulty": "easy"}, {"question": {"ja": "「夏は脱水症状に気をつけます」と言う理由は？", "vi": "Lý do \"Mùa hè phải cảnh báo mất nước\":"}, "options": [{"ja": "夏は寒いからです", "vi": "Vì mùa hè lạnh"}, {"ja": "夏は暑いからです", "vi": "Vì mùa hè nóng"}, {"ja": "夏は雨が多いからです", "vi": "Vì mùa hè mưa nhiều"}, {"ja": "夏は風が強いからです", "vi": "Vì mùa hè gió mạnh"}], "correct": 1, "explanation": {"ja": "夏は暑いので、脱水症状を起こしやすくなります。", "vi": "Vì mùa hè nóng nên dễ bị mất nước."}, "difficulty": "medium"}, {"question": {"ja": "秋から冬への季節の変わり目に気をつけることは？", "vi": "Khi chuyển mùa từ thu sang đông phải chú ý gì?"}, "options": [{"ja": "脱水症状", "vi": "Mất nước"}, {"ja": "風邪や感染症", "vi": "Cảm lạnh và bệnh truyền nhiễm"}, {"ja": "中毒症状", "vi": "Ngộ độc"}, {"ja": "日焼け", "vi": "Cháy nắng"}], "correct": 1, "explanation": {"ja": "秋から冬への季節の変わり目は、風邪やインフルエンザなどの感染症が増えるので、気をつける必要があります。", "vi": "Khi chuyển mùa từ thu sang đông, cảm lạnh và cúm dễ lây lan, nên phải cảnh báo."}, "difficulty": "medium"}, {"question": {"ja": "患者さんに「今年も冬が近づいています。風邪に気をつけましょう」と言う場合、適切ですか？", "vi": "Khi nói với người được chăm sóc \"Năm nay mùa đông sắp tới. Cẩn thận với cảm lạnh\" có thích hợp không?"}, "options": [{"ja": "はい、適切です", "vi": "Vâng, thích hợp"}, {"ja": "いいえ、患者さんは季節の変化に敏感なので、怖がります", "vi": "Không, người được chăm sóc nhạy cảm với thay đổi mùa nên sẽ sợ"}, {"ja": "いいえ、冬は関係ありません", "vi": "Không, mùa đông không liên quan"}, {"ja": "いいえ、患者さんはすでに風邪を持っています", "vi": "Không, người được chăm sóc đã có cảm lạnh"}], "correct": 0, "explanation": {"ja": "季節の変わり目に健康管理を呼びかけるのは、患者さんの健康を守るため適切です。", "vi": "Nhắc nhở quản lý sức khỏe khi chuyển mùa là thích hợp để bảo vệ sức khỏe người được chăm sóc."}, "difficulty": "hard"}]',
  8,
  10
);

-- ================================
-- Unit 3: 家族・人（Lesson 9-12）
-- ================================

-- Lesson 3-1: 家族の呼び方
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 3-1: 家族の呼び方", "vi": "Unit 3-1: Cách gọi các thành viên gia đình"}',
  '{"type": "vocabulary", "unit": 3, "lesson_number": 1, "intro": {"ja": "利用者さんの家族について聞く時、正しい家族の名前を知ることは大切です。また、敬語での家族の呼び方も学びましょう。", "vi": "Khi hỏi về gia đình người được chăm sóc, biết tên đúng của gia đình là quan trọng. Cũng học cách gọi gia đình bằng tiếng敬語."}, "words": [{"word": "お父さん", "reading": "おとうさん", "kanji": null, "meaning": {"vi": "Bố (lịch sự)", "ja": "他の人の父親を指す敬語表現"}, "examples": [{"ja": "○○さんのお父さんはどこに住んでいますか？", "vi": "Bố của ○○ san sống ở đâu?"}, {"ja": "お父さんはお元気ですか？", "vi": "Bố khỏe không?"}], "care_example": {"ja": "利用者さんの家族状況を聞く時：「ご家族はお父さんいますか？」", "vi": "Khi hỏi tình hình gia đình: \"Ông bố có trong gia đình bạn không?\""}}, {"word": "お母さん", "reading": "おかあさん", "kanji": null, "meaning": {"vi": "Mẹ (lịch sự)", "ja": "他の人の母親を指す敬語表現"}, "examples": [{"ja": "○○さんのお母さんはお元気ですか？", "vi": "Mẹ của ○○ san khỏe không?"}, {"ja": "お母さんは毎週来られますか？", "vi": "Mẹ có đến thăm mỗi tuần không?"}], "care_example": {"ja": "家族訪問時：「お母さんに○○さんの体調をお話しします。」", "vi": "Khi gia đình thăm: \"Tôi sẽ nói với mẹ về sức khỏe của ○○ san.\""}}]}',
  '[{"question": {"ja": "他人の父親を敬語で呼ぶ時は？", "vi": "Khi gọi bố của người khác bằng tiếng敬語:"}, "options": [{"ja": "父さん", "vi": "Otousan (không tôn trọng)"}, {"ja": "お父さん", "vi": "Otousan (tôn trọng)"}, {"ja": "父", "vi": "Chichi"}, {"ja": "親父", "vi": "Oyaji"}], "correct": 1, "explanation": {"ja": "他人の父親は「お父さん」と敬語で呼びます。", "vi": "Gọi bố của người khác là \"Otousan\" (敬語)."}, "difficulty": "easy"}, {"question": {"ja": "患者さんに「お兄さんはいますか？」と聞く場合、正しい言い方ですか？", "vi": "Khi hỏi người được chăm sóc \"Có anh trai không?\" cách nói đúng không?"}, "options": [{"ja": "はい、正しいです", "vi": "Vâng, đúng"}, {"ja": "いいえ、\"兄さん\"と言うべきです", "vi": "Không, nên nói \"Anh trai\""}, {"ja": "いいえ、\"お兄さんはいますか？\"の代わりに\"兄さんはいますか？\"と言うべきです", "vi": "Không, nên nói \"Anh trai có không?\" thay vì \"Anh trai (敬語) có không?\""}, {"ja": "いいえ、この質問は失礼です", "vi": "Không, câu hỏi này bất lịch sự"}], "correct": 0, "explanation": {"ja": "「お兄さんはいますか？」は正しい敬語です。患者さんの家族について敬語で聞くのが礼儀です。", "vi": "\"Oniisan wa imasu ka?\" (敬語) là đúng. Hỏi về gia đình người được chăm sóc bằng敬語là lịch sự."}, "difficulty": "medium"}, {"question": {"ja": "患者さんの娘さんが訪問に来た時、患者さんに「お嬢さんですね」と言うのは正しいですか？", "vi": "Khi con gái người được chăm sóc đến thăm, nói \"Đây là con gái bạn nhỉ\" có đúng không?"}, "options": [{"ja": "はい、正しいです", "vi": "Vâng, đúng"}, {"ja": "いいえ、\"娘さん\"と言うべきです", "vi": "Không, nên nói \"Con gái\""}, {"ja": "いいえ、この表現は失礼です。\"お嬢さん\"は未婚の女性に対して使う敬語です", "vi": "Không, biểu hiện này bất lịch sự. \"Ojousan\" dùng cho phụ nữ chưa lập gia đình"}, {"ja": "いいえ、詮索になるので言うべきではありません", "vi": "Không, không nên nói vì đó là sự tò mò"}], "correct": 1, "explanation": {"ja": "患者さんの娘さんについて話す時は「娘さん」が自然です。\"お嬢さん\"は成人前の未婚の女性に対して使う敬語です。", "vi": "Nói về con gái của người được chăm sóc thì \"Musume san\" (con gái) là tự nhiên. \"Ojousan\" dùng cho phụ nữ chưa lập gia đình."}, "difficulty": "hard"}, {"question": {"ja": "患者さんの孫さんが訪問に来た時、最も適切な言い方は？", "vi": "Khi cháu của người được chăm sóc đến thăm, cách nói thích hợp nhất:"}, "options": [{"ja": "「孫さんですね」", "vi": "\"Cháu bạn nhỉ\""}, {"ja": "「おしゃかですね」", "vi": "Không đúng"}, {"ja": "「お孫さんですね」", "vi": "\"Con cháu bạn nhỉ\""}, {"ja": "「ひ孫さんですね」", "vi": "\"Cháu cháu bạn nhỉ\""}], "correct": 2, "explanation": {"ja": "患者さんの孫については「お孫さん」と敬語で呼びます。", "vi": "Gọi cháu của người được chăm sóc là \"Omago san\" (敬語)."}, "difficulty": "hard"}, {"question": {"ja": "患者さんに「ご家族はお元気ですか？」と聞く場合、敬語の使い方は正しいですか？", "vi": "Khi hỏi người được chăm sóc \"Gia đình bạn khỏe không?\" cách dùng敬語đúng không?"}, "options": [{"ja": "はい、正しいです", "vi": "Vâng, đúng"}, {"ja": "いいえ、\"ご家族\"ではなく\"家族\"と言うべきです", "vi": "Không, nên nói \"Gia đình\" chứ không phải \"Gia đình (敬語)\""}, {"ja": "いいえ、\"お元気\"ではなく\"元気\"と言うべきです", "vi": "Không, nên nói \"Khỏe\" chứ không phải \"Khỏe (敬語)\""}, {"ja": "いいえ、この表現は家族に対して失礼です", "vi": "Không, biểu hiện này bất lịch sự với gia đình"}], "correct": 0, "explanation": {"ja": "「ご家族はお元気ですか？」は敬語を正しく使った丁寧な質問です。患者さんの家族について敬語で聞くことで、相手を尊重する気持ちを表します。", "vi": "\"Goka zoku wa ogenki desu ka?\" là câu hỏi lịch sự dùng敬語đúng. Hỏi về gia đình người được chăm sóc bằng敬語để thể hiện sự tôn trọng."}, "difficulty": "hard"}]',
  9,
  10
);

-- Lesson 3-2: 人物の特徴を表す言葉
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 3-2: 人物の特徴を表す言葉", "vi": "Unit 3-2: Từ để mô tả đặc điểm của người"}',
  '{"type": "vocabulary", "unit": 3, "lesson_number": 2, "intro": {"ja": "利用者さんや同僚について説明する時、適切な表現を使うことは大切です。尊敬と思いやりを込めた表現を学びましょう。", "vi": "Khi mô tả người được chăm sóc hoặc đồng nghiệp, sử dụng biểu hiện thích hợp là quan trọng. Hãy học biểu hiện đầy tôn trọng và lòng thương xót."}, "words": [{"word": "優しい", "reading": "やさしい", "kanji": "優しい", "meaning": {"vi": "Tốt bụng, dịu dàng", "ja": "心が温かく、思いやりのある様子"}, "examples": [{"ja": "この先生はとても優しいです。", "vi": "Cô giáo này rất tốt bụng."}, {"ja": "田中さんは優しい人です。", "vi": "Tanaka san là người tốt bụng."}], "care_example": {"ja": "利用者さんについて：「○○さんは優しい人です。みんなに親切にしています。」", "vi": "Về người được chăm sóc: \"○○ san là người tốt bụng. Anh ấy tốt với mọi người.\""}}]}',
  '[{"question": {"ja": "\"優しい\"という言葉はどんな人を表しますか？", "vi": "Từ \"Yasashii\" mô tả người như thế nào?"}, "options": [{"ja": "力が強い人", "vi": "Người mạnh mẽ"}, {"ja": "心が温かく、思いやりのある人", "vi": "Người có tấm lòng ấm áp và lòng thương xót"}, {"ja": "美しい人", "vi": "Người đẹp"}, {"ja": "聡い人", "vi": "Người thông minh"}], "correct": 1, "explanation": {"ja": "\"優しい\"は心が温かく、思いやりのある人を表します。", "vi": "\"Yasashii\" mô tả người có tấm lòng ấm áp và lòng thương xót."}, "difficulty": "easy"}, {"question": {"ja": "患者さんについて「この方は非常に優しい方です」と言う場合、失礼がありますか？", "vi": "Khi nói về người được chăm sóc \"Vị này là người rất tốt bụng\" có bất lịch sự không?"}, "options": [{"ja": "はい、敬語がありますから失礼がありません", "vi": "Vâng, vì có敬語nên không bất lịch sự"}, {"ja": "いいえ、敬語がありますから失礼がありません", "vi": "Không, vì có敬語nên không bất lịch sự"}, {"ja": "いいえ、敬語がありますから失礼があります", "vi": "Không, vì có敬語nên bất lịch sự"}, {"ja": "判断できません", "vi": "Không thể xác định"}], "correct": 1, "explanation": {"ja": "\"この方は非常に優しい方です\"は敬語が適切に使われているので、失礼ではありません。", "vi": "\"Kono kata wa hijou ni yasashii kata desu\" sử dụng敬語đúng nên không bất lịch sự."}, "difficulty": "hard"}]',
  10,
  10
);

-- Lesson 3-3: 年齢と世代
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 3-3: 年齢と世代", "vi": "Unit 3-3: Tuổi và thế hệ"}',
  '{"type": "vocabulary", "unit": 3, "lesson_number": 3, "intro": {"ja": "介護の現場では、利用者さんの年齢を確認したり、世代について理解したりすることが大切です。適切な表現を学びましょう。", "vi": "Ở cơ sở chăm sóc, xác nhận tuổi của người được chăm sóc và hiểu các thế hệ là quan trọng. Hãy học biểu hiện thích hợp."}, "words": [{"word": "高齢者", "reading": "こうれいしゃ", "kanji": "高齢者", "meaning": {"vi": "Người cao tuổi", "ja": "65歳以上の人（通常）"}, "examples": [{"ja": "この施設は高齢者向けです。", "vi": "Cơ sở này dành cho người cao tuổi."}, {"ja": "高齢者は転倒に気をつける必要があります。", "vi": "Người cao tuổi phải cảnh báo ngã."}], "care_example": {"ja": "利用者さんの年齢層について：「当施設は高齢者向けのサービスです。」", "vi": "Về lứa tuổi người được chăm sóc: \"Cơ sở này cung cấp dịch vụ cho người cao tuổi.\""}}]}',
  '[{"question": {"ja": "\"高齢者\"はどれくらいの年齢の人ですか？", "vi": "\"Koureisha\" (người cao tuổi) là người bao tuổi?"}, "options": [{"ja": "40歳以上", "vi": "Từ 40 tuổi trở lên"}, {"ja": "50歳以上", "vi": "Từ 50 tuổi trở lên"}, {"ja": "65歳以上", "vi": "Từ 65 tuổi trở lên"}, {"ja": "75歳以上", "vi": "Từ 75 tuổi trở lên"}], "correct": 2, "explanation": {"ja": "通常、\"高齢者\"は65歳以上の人を指します。ただし、定義は国や時代によって異なります。", "vi": "Thông thường, \"Koureisha\" là người từ 65 tuổi trở lên. Tuy nhiên, định nghĩa khác nhau tùy theo quốc gia và thời đại."}, "difficulty": "medium"}, {"question": {"ja": "患者さんが75歳の場合、\"高齢者\"と呼ぶことは失礼ですか？", "vi": "Nếu người được chăm sóc 75 tuổi, gọi \"người cao tuổi\" có bất lịch sự không?"}, "options": [{"ja": "はい、失礼です", "vi": "Vâng, bất lịch sự"}, {"ja": "いいえ、失礼ではありません", "vi": "Không, không bất lịch sự"}, {"ja": "状況によって異なります", "vi": "Tùy theo tình huống"}, {"ja": "判断できません", "vi": "Không thể xác định"}], "correct": 2, "explanation": {"ja": "\"高齢者\"は公式な医療・福祉用語なので、適切な文脈では失礼ではありません。ただし、直接相手に向かって\"高齢者だね\"と言うことは失礼かもしれません。", "vi": "\"Koureisha\" là thuật ngữ chính thức y tế/phúc lợi, nên trong bối cảnh thích hợp không bất lịch sự. Tuy nhiên, nói trực tiếp với người \"Bạn là người cao tuổi\" có thể bất lịch sự."}, "difficulty": "hard"}]',
  11,
  10
);

-- Lesson 3-4: 職業と役割
INSERT INTO lessons (id, course_id, title, content, quiz_data, sort_order, xp_reward) VALUES
(
  gen_random_uuid(),
  (SELECT id FROM courses WHERE jlpt_level = 'N5' AND category = 'vocabulary' LIMIT 1),
  '{"ja": "Unit 3-4: 職業と役割", "vi": "Unit 3-4: Công việc và vai trò"}',
  '{"type": "vocabulary", "unit": 3, "lesson_number": 4, "intro": {"ja": "介護施設では様々な職種の人が働いています。医師、看護師、介護士、栄養士など、各職業の役割を理解することは大切です。", "vi": "Ở cơ sở chăm sóc, nhiều ngành nghề khác nhau làm việc. Bác sĩ, y tá, nhân viên chăm sóc, dinh dưỡng... Hiểu vai trò của mỗi nghề là quan trọng."}, "words": [{"word": "看護師", "reading": "かんごし", "kanji": "看護師", "meaning": {"vi": "Y tá", "ja": "医療施設で患者の健康管理と治療を支援する職業"}, "examples": [{"ja": "看護師は患者さんの健康を管理します。", "vi": "Y tá quản lý sức khỏe của bệnh nhân."}, {"ja": "この看護師はとても経験豊かです。", "vi": "Y tá này rất có kinh nghiệm."}], "care_example": {"ja": "役割説明：「看護師は薬の管理と医学的なケアを行います。」", "vi": "Giải thích vai trò: \"Y tá quản lý thuốc và chăm sóc y học.\""}}, {"word": "介護士", "reading": "かいごし", "kanji": "介護士", "meaning": {"vi": "Nhân viên chăm sóc", "ja": "日常のケアと生活支援を行う職業"}, "examples": [{"ja": "介護士は患者さんの日常生活を手伝います。", "vi": "Nhân viên chăm sóc giúp đỡ hoạt động hàng ngày của bệnh nhân."}, {"ja": "介護士のサポートで患者さんは安心です。", "vi": "Nhờ sự hỗ trợ của nhân viên chăm sóc, bệnh nhân yên tâm."}], "care_example": {"ja": "職種説明：「介護士はお風呂、食事、排泄などのお手伝いをします。」", "vi": "Giải thích nghề: \"Nhân viên chăm sóc giúp đỡ tắm, ăn, vệ sinh v.v.\""}}, {"word": "医師", "reading": "いし", "kanji": "医師", "meaning": {"vi": "Bác sĩ", "ja": "医学の専門家で患者の診断と治療を行う職業"}, "examples": [{"ja": "医師の診察を受けました。", "vi": "Tôi đã khám với bác sĩ."}, {"ja": "医師は患者さんの治療計画を立てます。", "vi": "Bác sĩ lập kế hoạch điều trị cho bệnh nhân."}], "care_example": {"ja": "医療判断：「医師の指示に従って薬を投与します。」", "vi": "Quyết định y tế: \"Cung cấp thuốc theo hướng dẫn của bác sĩ.\""}}]}',
  '[{"question": {"ja": "介護施設で最も患者さんと接する時間が長い職業は？", "vi": "Ở cơ sở chăm sóc, nghề nào tiếp xúc với bệnh nhân lâu nhất?"}, "options": [{"ja": "医師", "vi": "Bác sĩ"}, {"ja": "看護師", "vi": "Y tá"}, {"ja": "介護士", "vi": "Nhân viên chăm sóc"}, {"ja": "栄養士", "vi": "Dinh dưỡng"}], "correct": 2, "explanation": {"ja": "介護士は患者さんの日常生活全般をサポートするため、最も長い時間を一緒に過ごします。", "vi": "Nhân viên chăm sóc hỗ trợ toàn bộ cuộc sống hàng ngày của bệnh nhân, nên dành nhiều thời gian nhất cùng họ."}, "difficulty": "medium"}, {"question": {"ja": "医師と看護師の役割の違いは？", "vi": "Sự khác nhau giữa vai trò của bác sĩ và y tá:"}, "options": [{"ja": "違いはありません", "vi": "Không có sự khác nhau"}, {"ja": "医師は治療計画を立てて、看護師はその計画を実行します", "vi": "Bác sĩ lập kế hoạch điều trị, y tá thực hiện kế hoạch"}, {"ja": "看護師は医師より学位が高いです", "vi": "Y tá có bằng cấp cao hơn bác sĩ"}, {"ja": "医師は薬だけを扱います", "vi": "Bác sĩ chỉ xử lý thuốc"}], "correct": 1, "explanation": {"ja": "医師は診断と治療計画、看護師はその計画の実行とモニタリングを担当します。", "vi": "Bác sĩ chịu trách nhiệm chẩn đoán và lập kế hoạch điều trị, y tá thực hiện kế hoạch và giám sát."}, "difficulty": "hard"}, {"question": {"ja": "患者さんが「医師に会いたいです」と言った場合、介護士としての対応は？", "vi": "Khi bệnh nhân nói \"Tôi muốn gặp bác sĩ\" nhân viên chăm sóc nên làm gì?"}, "options": [{"ja": "医師に直接言う", "vi": "Nói trực tiếp với bác sĩ"}, {"ja": "患者さんの要望を記録して、医師または看護師に報告する", "vi": "Ghi lại yêu cầu của bệnh nhân và báo cáo cho bác sĩ hoặc y tá"}, {"ja": "医師の時間がないので、代わりに対応する", "vi": "Vì bác sĩ bận nên tôi sẽ xử lý thay"}, {"ja": "何もしない", "vi": "Không làm gì"}], "correct": 1, "explanation": {"ja": "介護士は患者さんの要望を記録して、医師または看護師に報告する責任があります。", "vi": "Nhân viên chăm sóc có trách nhiệm ghi lại yêu cầu của bệnh nhân và báo cáo cho bác sĩ hoặc y tá."}, "difficulty": "hard"}]',
  12,
  10
);
